import React, { useState, useEffect } from 'react';

const Fruits = () => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    setIsVisible(true);
  }, []);

  const fruits = [
    {
      id: 1,
      name: 'Apple',
      price: '₹120/kg',
      image: 'https://via.placeholder.com/200x200/FF6B6B/FFFFFF?text=Apple',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Apple%20-%20₹120/kg'
    },
    {
      id: 2,
      name: 'Banana',
      price: '₹40/dozen',
      image: 'https://via.placeholder.com/200x200/FFD700/FFFFFF?text=Banana',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Banana%20-%20₹40/dozen'
    },
    {
      id: 3,
      name: 'Orange',
      price: '₹60/kg',
      image: 'https://via.placeholder.com/200x200/FFA500/FFFFFF?text=Orange',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Orange%20-%20₹60/kg'
    },
    {
      id: 4,
      name: 'Grapes',
      price: '₹100/kg',
      image: 'https://via.placeholder.com/200x200/90EE90/FFFFFF?text=Grapes',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Grapes%20-%20₹100/kg'
    },
    {
      id: 5,
      name: 'Mango',
      price: '₹80/kg',
      image: 'https://via.placeholder.com/200x200/FF6347/FFFFFF?text=Mango',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Mango%20-%20₹80/kg'
    },
    {
      id: 6,
      name: 'Pineapple',
      price: '₹45/pc',
      image: 'https://via.placeholder.com/200x200/FFE66D/FFFFFF?text=Pineapple',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Pineapple%20-%20₹45/pc'
    },
    {
      id: 7,
      name: 'Pomegranate',
      price: '₹150/kg',
      image: 'https://via.placeholder.com/200x200/FF1493/FFFFFF?text=Pomegranate',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Pomegranate%20-%20₹150/kg'
    },
    {
      id: 8,
      name: 'Guava',
      price: '₹50/kg',
      image: 'https://via.placeholder.com/200x200/32CD32/FFFFFF?text=Guava',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Guava%20-%20₹50/kg'
    },
    {
      id: 9,
      name: 'Papaya',
      price: '₹35/pc',
      image: 'https://via.placeholder.com/200x200/FFB6C1/FFFFFF?text=Papaya',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Papaya%20-%20₹35/pc'
    },
    {
      id: 10,
      name: 'Jamun',
      price: '₹80/kg',
      image: 'https://via.placeholder.com/200x200/9370DB/FFFFFF?text=Jamun',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Jamun%20-%20₹80/kg'
    },
    {
      id: 11,
      name: 'Sweet Lime',
      price: '₹40/kg',
      image: 'https://via.placeholder.com/200x200/FF8C00/FFFFFF?text=Sweet%20Lime',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Sweet%20Lime%20-%20₹40/kg'
    },
    {
      id: 12,
      name: 'Watermelon',
      price: '₹25/pc',
      image: 'https://via.placeholder.com/200x200/FF69B4/FFFFFF?text=Watermelon',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Watermelon%20-%20₹25/pc'
    }
  ];

  return (
    <div className="fruits-page">
      {/* Page Header */}
      <section className="page-header bg-gradient-to-r from-fresh-green to-light-green text-white py-32 text-center">
        <div className="max-w-7xl mx-auto px-5">
          <h1 className={`text-5xl font-bold mb-4 transition-all duration-1000 transform ${
            isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
          }`}>
            Fresh Fruits
          </h1>
          <p className="text-xl">Seasonal and fresh fruits delivered daily</p>
        </div>
      </section>

      {/* Fruits Grid */}
      <section className="products-section bg-white py-16">
        <div className="max-w-7xl mx-auto px-5">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {fruits.map((fruit, index) => (
              <div 
                key={fruit.id}
                className={`bg-gray-50 rounded-xl overflow-hidden transition-all transform hover:-translate-y-2 hover:shadow-xl ${
                  isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
                }`}
                style={{ transitionDelay: `${index * 50}ms` }}
              >
                <img 
                  src={fruit.image} 
                  alt={fruit.name} 
                  className="w-full h-48 object-cover"
                />
                <div className="p-6 text-center">
                  <h3 className="text-xl font-semibold mb-2 text-gray-800">{fruit.name}</h3>
                  <p className="text-lg font-bold text-fresh-green mb-4">{fruit.price}</p>
                  <a 
                    href={fruit.whatsappLink} 
                    className="bg-whatsapp hover:bg-green-600 text-white px-4 py-2 rounded-lg font-semibold transition-all" 
                    target="_blank" 
                    rel="noopener noreferrer"
                  >
                    <i className="fab fa-whatsapp mr-2"></i> Order on WhatsApp
                  </a>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Quick Order Section */}
      <section className="quick-order bg-gray-50 py-16 text-center">
        <div className="max-w-7xl mx-auto px-5">
          <div className="quick-order-content">
            <h2 className="text-3xl font-bold mb-4 text-fresh-green">Quick Order</h2>
            <p className="text-lg mb-8 text-gray-600">Can't find what you're looking for? Message us on WhatsApp!</p>
            <a 
              href="https://wa.me/919876543210?text=Hi%20I%20want%20to%20order%20fruits" 
              className="bg-fresh-green hover:bg-green-800 text-white px-8 py-4 rounded-lg font-semibold text-lg transition-all transform hover:-translate-y-1" 
              target="_blank" 
              rel="noopener noreferrer"
            >
              <i className="fab fa-whatsapp mr-2"></i> Order Custom Fruits
            </a>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Fruits;
